// hobson-instance renderer
export async function render(item, api) {
  const instanceId = item.id;
  const KERNEL_CORE_ID = '33333333-1111-0000-0000-000000000000';

  // Create storage backend adapter with ID prefixing
  const storageBackend = {
    async get(id) {
      const prefixedId = `${instanceId}:${id}`;
      return await api.get(prefixedId);
    },

    async set(item) {
      const prefixedItem = {
        ...item,
        id: `${instanceId}:${item.id}`
      };
      return await api.set(prefixedItem);
    },

    async delete(id) {
      const prefixedId = `${instanceId}:${id}`;
      return await api.delete(prefixedId);
    },

    async query(filter) {
      // Get all items from parent
      const allItems = await api.getAll();

      // Filter to only this instance's items (by prefix)
      const instanceItems = allItems.filter(item => 
        item.id.startsWith(`${instanceId}:`)
      );

      // Strip prefix from IDs
      const unprefixed = instanceItems.map(item => ({
        ...item,
        id: item.id.slice(instanceId.length + 1)
      }));

      // Apply filter
      return unprefixed.filter(item => {
        for (const [key, value] of Object.entries(filter)) {
          if (item[key] !== value) return false;
        }
        return true;
      });
    },

    async getAll() {
      const allItems = await api.getAll();
      const instanceItems = allItems.filter(item => 
        item.id.startsWith(`${instanceId}:`)
      );
      return instanceItems.map(item => ({
        ...item,
        id: item.id.slice(instanceId.length + 1)
      }));
    }
  };

  // Create custom require function that loads modules with prefixed IDs
  const createNestedRequire = () => {
    return async function require(moduleId) {
      // Load the prefixed item from parent storage
      const prefixedId = `${instanceId}:${moduleId}`;

      try {
        const item = await api.get(prefixedId);

        if (!item?.content?.code) {
          throw new Error(`Module has no code: ${moduleId}`);
        }

        // Evaluate as ES module
        const code = `
          "use strict";
          ${item.content.code}
          //# sourceURL=${item.name || moduleId + '.js'}
        `;
        const blob = new Blob([code], { type: 'application/javascript' });
        const url = URL.createObjectURL(blob);

        try {
          const module = await import(url);
          return module;
        } finally {
          URL.revokeObjectURL(url);
        }
      } catch (error) {
        if (error.message.includes('not found')) {
          throw new Error(`Nested kernel module not found: ${moduleId}`);
        }
        throw error;
      }
    };
  };

  // Container element
  const container = document.createElement('div');
  container.style.cssText = `
    width: 100%;
    height: 100%;
    border: 2px solid #0066cc;
    border-radius: 4px;
    overflow: hidden;
    display: flex;
    flex-direction: column;
  `;

  // Header showing this is a nested instance
  const header = document.createElement('div');
  header.style.cssText = `
    background: #0066cc;
    color: white;
    padding: 8px 12px;
    font-size: 12px;
    font-weight: bold;
    display: flex;
    justify-content: space-between;
    align-items: center;
  `;
  header.textContent = `Nested Hobson Instance: ${item.name || instanceId.slice(0, 8)}`;

  // Add REPL toggle button
  const replBtn = document.createElement('button');
  replBtn.textContent = 'Toggle REPL';
  replBtn.style.cssText = 'padding: 4px 12px; background: white; color: #0066cc; border: none; border-radius: 3px; cursor: pointer; font-size: 12px;';
  replBtn.onclick = async () => {
    if (nestedKernel) {
      await nestedKernel.repl.toggle();
    }
  };
  header.appendChild(replBtn);

  // Body where nested kernel renders
  const body = document.createElement('div');
  body.style.cssText = `
    flex: 1;
    overflow: auto;
    background: white;
  `;

  container.appendChild(header);
  container.appendChild(body);

  // Try to boot the nested kernel
  let nestedKernel = null;
  try {
    // Check if nested kernel exists
    const prefixedKernelId = `${instanceId}:${KERNEL_CORE_ID}`;
    await api.get(prefixedKernelId);

    // Kernel exists - boot it!
    const nestedRequire = createNestedRequire();
    const { loadKernel } = await nestedRequire(KERNEL_CORE_ID);
    const Kernel = await loadKernel(nestedRequire, storageBackend);
    const kernel = new Kernel();

    // Boot the kernel
    await kernel.boot();

    // Store kernel reference for REPL button
    nestedKernel = kernel;

    // Append kernel's root element to our body
    body.appendChild(kernel.rootElement);

  } catch (error) {
    // Kernel not found - show import UI
    if (error.message.includes('not found')) {
      body.innerHTML = `
        <div style="padding: 40px; text-align: center;">
          <h2 style="color: #0066cc;">Nested Hobson Instance</h2>
          <p>No kernel found. Import <code>initial-kernel.json</code> to initialize this instance.</p>
          <p style="margin-top: 20px;">
            <input type="file" accept=".json" id="import-${instanceId}" style="display: none;" />
            <button id="import-btn-${instanceId}" style="padding: 10px 20px; background: #0066cc; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 14px;">
              Import Kernel JSON
            </button>
          </p>
          <p style="color: #666; font-size: 12px; margin-top: 20px;">Items will be stored with instance prefix: <code>${instanceId}:</code></p>
        </div>
      `;

      // Handle import
      const fileInput = body.querySelector(`#import-${instanceId}`);
      const importBtn = body.querySelector(`#import-btn-${instanceId}`);

      importBtn.onclick = () => fileInput.click();

      fileInput.onchange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        try {
          const text = await file.text();
          const data = JSON.parse(text);
          const items = Array.isArray(data) ? data : [data];

          // Import all items with prefix
          for (const importItem of items) {
            const prefixedItem = {
              ...importItem,
              id: `${instanceId}:${importItem.id}`
            };
            await api.set(prefixedItem);
          }

          // Show success message
          body.innerHTML = `
            <div style="padding: 40px; text-align: center; color: green;">
              <h2>Import Successful!</h2>
              <p>Imported ${items.length} items.</p>
              <p style="margin-top: 20px;">
                <button id="reload-btn" style="padding: 10px 20px; background: #0066cc; color: white; border: none; border-radius: 4px; cursor: pointer;">
                  Boot Kernel
                </button>
              </p>
            </div>
          `;

          // Reload button triggers re-render
          body.querySelector('#reload-btn').onclick = async () => {
            await api.update(item);
          };

        } catch (error) {
          body.innerHTML += `
            <div style="color: red; margin-top: 20px; padding: 0 40px;">
              <strong>Error:</strong> ${error.message}
            </div>
          `;
        }
      };

    } else {
      // Other error during boot
      body.innerHTML = `
        <div style="padding: 40px; color: red;">
          <h3>Boot Error</h3>
          <pre style="background: #fee; padding: 10px; overflow: auto;">${error.message}</pre>
          <pre style="background: #fee; padding: 10px; overflow: auto; font-size: 11px;">${error.stack}</pre>
        </div>
      `;
    }
  }

  return container;
}
